document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("xrhseis");e&&setTimeout(()=>{(async()=>{try{e.innerHTML='<option value=""></option>',e.disabled=!0;const t=document.querySelector('input[name="_csrf"]')?.value||document.querySelector('meta[name="csrf-token"]')?.content,n=await fetch("/api/xrhseis",{method:"GET",headers:{"Content-Type":"application/json",...t&&{"CSRF-Token":t}},credentials:"include"});if(401===n.status)return e.innerHTML='<option value=""></option>',void(e.disabled=!0);if(!n.ok)throw new Error(`HTTP ${n.status}: ${n.statusText}`);const o=n.headers.get("content-type");if(!o||!o.includes("application/json"))throw new Error("Response is not JSON");const r=await n.text();if(!r||""===r.trim())throw new Error("Empty response from server");const i=JSON.parse(r);if(!Array.isArray(i.xrhseis))throw new Error("Invalid data format");if(e.innerHTML='<option value="" selected></option>',e.disabled=!1,0===i.xrhseis.length)return e.innerHTML='<option value=""></option>',void(e.disabled=!0);i.xrhseis.forEach(t=>{const n=new Option(t.etos,t.etos);e.appendChild(n)})}catch(t){console.error("Error loading years:",t),e.innerHTML='<option value="">Σφάλμα φόρτωσης</option>',e.disabled=!0}})()},100)});